// 팀별 한국선수 27명 + 외국인 1명 = 28명(꽉 채운 스쿼드) 풀 생성
// needs(buildSquad)와 동일한 분포: GK2,CB4,RB2,LB2,CDM2,CM3,CAM2,RW2,LW2,ST3,CF1 = 25
const KLEAGUE_POS_TEMPLATE=["GK","GK","CB","CB","CB","CB","RB","RB","LB","LB","CDM","CDM","CM","CM","CM","CAM","CAM","RW","RW","LW","LW","ST","ST","ST","CF"];
const FOREIGN_ELIGIBLE=["ST","CF","CAM","CM","CB"];
const KLEAGUE_PLAYERS=[];
K_TEAMS.forEach(tid=>{
  const template=[...KLEAGUE_POS_TEMPLATE];
  // 외국인 선수가 맡을 포지션 1개 선정 (공격/중원/수비 핵심 중)
  const foreignEligibleIdx=template.map((p,i)=>FOREIGN_ELIGIBLE.includes(p)?i:-1).filter(i=>i>=0);
  const foreignSlotIdx=foreignEligibleIdx[Math.floor(Math.random()*foreignEligibleIdx.length)];
  const foreignPos=template[foreignSlotIdx];
  template.splice(foreignSlotIdx,1); // 24개 남음
  // 추가 뎁스 3명 (랜덤 포지션, 28명 채우기용)
  for(let i=0;i<3;i++)template.push(KLEAGUE_POS_TEMPLATE[Math.floor(Math.random()*KLEAGUE_POS_TEMPLATE.length)]);
  // 한국 선수 27명 생성 (template 길이=27)
  template.forEach((pos,i)=>{
    const p=generateKDomesticPlayer(`${tid}_${i}`,tid);
    p.pos=pos; // 포지션 분포 고정
    KLEAGUE_PLAYERS.push(p);
  });
  // 외국인 1명
  const fp=generateKForeignPlayer(`${tid}_f`,tid);
  fp.pos=foreignPos;
  KLEAGUE_PLAYERS.push(fp);
});
// ─── 한국 선수 밸런스 조정 ───
// 손흥민·이강인·김민재·황희찬·황인범 등 슈퍼스타 5인은 그대로 유지하고,
// 그 외 한국 국적 선수(국내파/유스/K리그 포함)는 능력치·시장가치·연봉·명성을 대폭 하향 조정한다.
const KOREAN_NATS=new Set(["Korea Republic","South Korea"]);
const KOREAN_SUPERSTAR_IDS=new Set([
  "p200104", // 손흥민
  "m007",    // 이강인
  "m053",    // 김민재
  "m051",    // 황희찬
  "m008",    // 황인범
]);
function isKoreanNat(nat){return !!nat&&KOREAN_NATS.has(nat);}
const K_LEAGUE_CLUBS_FORCED=["ulsan_hd","jeonbuk","pohang","fc_seoul","gwangju_fc","daegu_fc","gangwon_fc","suwon_fc","daejeon","incheon","jeju_sk","gimcheon"];
function pickKLeagueClub(seed){const n=typeof seed==="string"?seed.split("").reduce((a,c)=>a+c.charCodeAt(0),0):seed;return K_LEAGUE_CLUBS_FORCED[Math.abs(n)%K_LEAGUE_CLUBS_FORCED.length];}
function nerfKoreanPlayer(p){
  if(!isKoreanNat(p.nat))return p;
  if(KOREAN_SUPERSTAR_IDS.has(p.id))return p; // 슈퍼스타는 너프 제외
  if(p.id==="p200104")return p; // 손흥민 너프 제외
  // 슈퍼스타 아닌 한국선수는 K리그 클럽 강제 배정
  const kClub=K_LEAGUE_CLUBS_FORCED.includes(p.club)?p.club:pickKLeagueClub(p.id);
  const dStat=(v,min)=>(typeof v!=="number")?v:Math.max(min,Math.round(v*0.78));
  const newRat=dStat(p.rat,40);
  const newPot=dStat(p.pot,45);
  return{
    ...p,
    club:kClub,
    rat:newRat,
    pot:(newPot!==undefined&&newRat!==undefined)?Math.max(newPot,newRat):newPot,
    pace:dStat(p.pace,30),sho:dStat(p.sho,28),pas:dStat(p.pas,30),
    dri:dStat(p.dri,28),def:dStat(p.def,28),phy:dStat(p.phy,30),
    val:Math.max(0.3,parseFloat((p.val*0.4).toFixed(1))),
    wage:Math.max(0.3,parseFloat((p.wage*0.4).toFixed(1))),
    fame:Math.max(15,Math.round((p.fame||40)*0.55)),
  };
}
// 선수단 연봉 평균 -15% 조정 (기존 등록 데이터 전체 적용, K리그 풀은 자체 공식에서 이미 반영됨)
const applyWageCut=p=>({...p,wage:parseFloat((p.wage*0.85).toFixed(1))});
// 전체 선수 기본값 주입: contract(1~4랜덤)
// wage가 없거나 0이면 val의 1% 수준으로 초기화
const _seed=(id)=>{let h=0;for(let i=0;i<id.length;i++){h=(Math.imul(31,h)+id.charCodeAt(i))|0;}return Math.abs(h);};
const applyPlayerDefaults=p=>{
  const s=_seed(p.id||"x");
  const contract=p.contract!==undefined?p.contract:(s%4)+1; // 1~4년
  const wage=(!p.wage||p.wage<=0)?parseFloat((p.val*0.01).toFixed(1)):p.wage;
  return{...p,wage,contract};
};
// ── 시장가 헬퍼: 난이도별 배수 적용 (입문×12, 일반×15, 하드×18, 리얼리스틱×22) ──
// difficulty는 런타임에 결정되므로 함수가 아닌 컴포넌트 내에서 사용
// 전역에서는 기본 ×15 사용
const BASE_MARKET_MULT=15;
const getBaseMarketVal=(p)=>parseFloat((p.val*BASE_MARKET_MULT).toFixed(1));
const ALL_PLAYERS = [...PLAYERS.map(applyWageCut), ...VIRTUAL_PLAYERS.map(applyWageCut), ...MODERN_PLAYERS.map(applyWageCut), ...KLEAGUE_PLAYERS].map(nerfKoreanPlayer).map(applyPlayerDefaults);

export {
  ALL_PLAYERS, KLEAGUE_PLAYERS, POS_POOL,
  nerfKoreanPlayer, applyPlayerDefaults,
  isKoreanNat, KOREAN_NATS, KOREAN_SUPERSTAR_IDS,
};